const { chromium } = require\('playwright'\);

\(async \(\) => {
  const browser = await chromium.launch\({ headless: false, slowMo: 500 }\);
  const page = await browser.newPage\(\);
  await page.setViewportSize\({ width: 1400, height: 900 }\);

  console.log\('Navigating...'\);
  await page.goto\('http://localhost:3000', { waitUntil: 'networkidle' }\);

  console.log\('Looking for input...'\);
  const input = await page.waitForSelector\('textarea', { timeout: 10000 }\);
  await input.click\(\);
  await input.fill\('Create a simple pricing card component'\);
  await page.keyboard.press\('Enter'\);

  console.log\('Waiting for generation...'\);
  // Wait for a response to appear
  await page.waitForTimeout\(5000\);

  // Wait until loading stops
  try {
    await page.waitForFunction\(\(\) => {
      const spinners = document.querySelectorAll\('[class*=\\"animate-spin\\"]'\);
      return spinners.length === 0;
    }, { timeout: 60000 }\);
  } catch\(e\) { console.log\('Timeout waiting for spinner'\); }

  await page.waitForTimeout\(2000\);
  await page.screenshot\({ path: 'C:/Users/hayat/AppData/Local/Temp/generated.png' }\);
  console.log\('Done - screenshot saved'\);
  await browser.close\(\);
}\)\(\).catch\(console.error\);
